/* AdminUserMapper.selectUserTotalCount */
SELECT
	COUNT(1)
FROM
	TB_USER_INFO


		AND MASTER_CODE = #{masterCode}


		AND CONFM_YN = #{confmYn}


		AND USE_YN = #{useYn}


		AND MEMBER_ID LIKE CONCAT('%', #{memberId}, '%')


		AND MEMBER_NM LIKE CONCAT('%', #{memberNm}, '%')

/* AdminUserMapper.selectUserList */ SELECT MEMBER_ID AS memberId ,AUTH_GRP_CD AS authGrpCd ,MEMBER_NM AS memberNm ,MEMBER_PW AS memberPw ,MASTER_CODE AS masterCode ,MEMBER_EMAIL AS memberEmail ,MEMBER_BRTHDY AS memberBrthdy ,MEMBER_PHONE AS memberPhone ,MEMBER_POST AS memberPost ,MEMBER_ADDR AS memberAddr ,MEMBER_ADDR_DETL AS memberAddrDetl ,CONFM_YN AS confmYn ,JOIN_DE AS joinDe ,CONFM_ID AS confmId ,CONFM_DT AS confmDt ,PASSWORD_UPD_DT AS passwordUpdDt ,LAST_LOGIN_DT AS lastLoginDt ,USE_YN AS useYn ,UPD_ID AS updId ,DATE_FORMAT(UPD_DT, '%Y-%m-%d %H:%i:%s') AS updDt ,FAIL_CNT AS failCnt FROM TB_USER_INFO
AND MASTER_CODE = #{masterCode}
AND CONFM_YN = #{confmYn}
AND USE_YN = #{useYn}
AND MEMBER_ID LIKE CONCAT('%', #{memberId}, '%')
AND MEMBER_NM LIKE CONCAT('%', #{memberNm}, '%')
ORDER BY JOIN_DE DESC LIMIT #{offset}, #{pageSize}

mapper.update:
/* AdminUserMapper.saveUser */
UPDATE TB_USER_INFO
SET
	 AUTH_GRP_CD 		= #{masterCode}
	,MEMBER_NM   		= #{memberNm}
	,MASTER_CODE 		= #{masterCode}
	,MEMBER_EMAIL 		= #{memberEmail}
	,MEMBER_BRTHDY		= #{memberBrthdy}
	,MEMBER_PHONE		= #{memberPhone}
	,MEMBER_POST 		= #{memberPost}
	,MEMBER_ADDR 		= #{memberAddr}
	,MEMBER_ADDR_DETL 	= #{memberAddrDetl}
	,CONFM_YN 			= #{confmYn}
	,CONFM_ID 			= #{userId}
	,CONFM_DT 			= now()
	,USE_YN 			= #{useYn}
	,UPD_ID 			= #{userId}
	,UPD_DT				= now()
WHERE
	MEMBER_ID = #{memberId}

/* AdminUserMapper.loginCountReset */
UPDATE TB_USER_INFO
SET
	 FAIL_CNT	= 0
	,UPD_ID 	= #{userId}
	,UPD_DT		= now()
WHERE
	MEMBER_ID = #{memberId}

