/* AdminUserMapper.selectLogTotalCount */ SELECT COUNT(1) FROM TB_LOGIN_HIS
AND DATE_FORMAT(LOGIN_DT, '%Y-%m-%d') BETWEEN #{startDate} AND #{endDate}
AND MEMBER_ID LIKE CONCAT('%', #{memberId}, '%')
AND MEMBER_NM LIKE CONCAT('%', #{memberNm}, '%')

/* AdminUserMapper.selectLogList */ SELECT A.MEMBER_ID AS memberId ,A.LOGIN_IP AS loginIp ,DATE_FORMAT(LOGIN_DT, '%Y-%m-%d %H:%i:%s') AS loginDt ,B.MEMBER_NM AS memberNm ,B.MEMBER_EMAIL AS memberEmail ,B.MEMBER_BRTHDY AS memberBrthdy ,B.MEMBER_PHONE AS memberPhone FROM TB_LOGIN_HIS A LEFT JOIN TB_USER_INFO B ON A.MEMBER_ID = B.MEMBER_ID
AND DATE_FORMAT(A.LOGIN_DT, '%Y-%m-%d') BETWEEN #{startDate} AND #{endDate}
AND A.MEMBER_ID LIKE CONCAT('%', #{memberId}, '%')
AND A.MEMBER_NM LIKE CONCAT('%', #{memberNm}, '%')
ORDER BY A.LOGIN_DT DESC LIMIT #{offset}, #{pageSize}
